 62→void ALFPTacticsUnit::BeginPlay()
 63→{
 64→    Super::BeginPlay();
 65→
 66→    // 注册到回合管理器
 67→    if (ALFPTurnManager* TurnManager = GetTurnManager())
 68→    {
 69→        TurnManager->RegisterUnit(this);
 70→    }
 71→
 72→    for (ULFPBetrayalCondition* Condition : BetrayalConditions)
 73→    {
 74→        if (Condition)
 75→        {
 76→            Condition->RegisterCondition(this);
 77→        }
 78→    }
 79→
 80→    FLFPHexCoordinates SpawnPoint = FLFPHexCoordinates(StartCoordinates_Q, StartCoordinates_R);
 81→    SetCurrentCoordinates(SpawnPoint);
 82→
 83→	// 初始化血量
 84→    CurrentHealth = MaxHealth;
 85→	InitializeHealthBar();
 86→
 87→    PlannedSkillIconComponent->SetRelativeLocation(FVector(0, SkillIconTopDist, 0)); // 在血条上方
 88→
 89→    // 设置移动时间线
 90→    if (MoveCurve)
 91→    {
 92→        FOnTimelineFloat TimelineCallback;
 93→        TimelineCallback.BindUFunction(this, FName("UpdateMoveAnimation"));
 94→        //MoveTimeline->AddInterpFloat(MoveCurve, TimelineCallback);
 95→
 96→        FOnTimelineEvent TimelineFinishedCallback;
 97→        TimelineFinishedCallback.BindUFunction(this, FName("FinishMove"));
 98→        //MoveTimeline->SetTimelineFinishedFunc(TimelineFinishedCallback);
 99→    }
100→
101→    // 如果是敌方单位，创建AI控制器
102→    if (IsEnemy())
103→    {
104→        FActorSpawnParameters SpawnParams;
105→        SpawnParams.Owner = this;
106→        SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
107→
108→        if (AIControllerClass)
109→        {
110→            AIController = GetWorld()->SpawnActor<ALFPAIController>(AIControllerClass, SpawnParams);
111→            if (AIController)
112→            {
113→                AIController->Possess(this);
114→                AIController->SetControlledUnit(this);
115→            }
116→        }
117→    }
118→}
