120→void ALFPTacticsUnit::EndPlay(const EEndPlayReason::Type EndPlayReason)
121→{
122→    Super::EndPlay(EndPlayReason);
123→
124→    if (ALFPTurnManager* TurnManager = GetTurnManager())
125→    {
126→        TurnManager->UnregisterUnit(this);
127→    }
128→
129→	for (ULFPBetrayalCondition* Condition : BetrayalConditions)
130→	{
131→		if (Condition)
132→		{
133→			Condition->UnRegisterCondition(this);
134→		}
135→	}
136→}
