138→void ALFPTacticsUnit::SetCurrentCoordinates(const FLFPHexCoordinates& NewCoords)
139→{
140→    // 清除旧位置
141→    if (ALFPHexGridManager* GridManager = GetGridManager())
142→    {
143→        if (ALFPHexTile* LastTile = GridManager->GetTileAtCoordinates(CurrentCoordinates))
144→        {
145→            LastTile->SetIsOccupied(false);
146→            LastTile->SetUnitOnTile(nullptr);
147→        }
148→        if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(NewCoords))
149→        {
150→            SetActorLocation(Tile->GetActorLocation() + FVector(0, 0, 1));
151→            Tile->SetIsOccupied(true);
152→            Tile->SetUnitOnTile(this);
153→            CurrentCoordinates = NewCoords;
154→        }
155→    }
156→}
