244→void ALFPTacticsUnit::UpdateMoveAnimation(float Value)
245→{
246→    if (CurrentPathIndex < 0 || CurrentPathIndex >= MovePath.Num() - 1) return;
247→
248→    // 获取当前和下一个格子
249→    ALFPHexTile* CurrentTile = MovePath[CurrentPathIndex];
250→    ALFPHexTile* NextTile = MovePath[CurrentPathIndex + 1];
251→
252→    if (!CurrentTile || !NextTile) return;
253→
254→    // 计算位置
255→    FVector StartPos = CurrentTile->GetActorLocation() + FVector(0, 0, 50);
256→    FVector EndPos = NextTile->GetActorLocation() + FVector(0, 0, 50);
257→
258→    // 应用插值
259→    FVector NewLocation = FMath::Lerp(StartPos, EndPos, Value);
260→    SetActorLocation(NewLocation);
261→
262→    // 更新朝向
263→    FVector Direction = (EndPos - StartPos).GetSafeNormal();
264→    if (!Direction.IsNearlyZero())
265→    {
266→        FRotator NewRotation = Direction.Rotation();
267→        SpriteComponent->SetWorldRotation(NewRotation);
268→    }
269→
270→    // 检查是否移动到下一段
271→    if (Value >= 1.0f)
272→    {
273→        CurrentPathIndex++;
274→        MoveProgress = 0.0f;
275→
