478→void ALFPTacticsUnit::TakeDamage(int32 Damage)
479→{
480→    if (bIsDead) return;
481→
482→	// 计算实际伤害（考虑防御）
483→	int32 ActualDamage = FMath::Max(Damage - Defense, 1);
484→	int32 OldHealth = CurrentHealth;
485→	CurrentHealth = FMath::Max(CurrentHealth - ActualDamage, 0);
486→
487→	// 广播血量变化事件
488→	OnHealthChangedDelegate.Broadcast(CurrentHealth, MaxHealth);
489→
490→	// 蓝图事件
491→	OnTakeDamage(ActualDamage);
492→
493→	// 检查死亡
494→	if (CurrentHealth <= 0)
495→	{
496→		HandleDeath();
497→	}
498→}
