546→void ALFPTacticsUnit::ApplyDamageToTarget(ALFPTacticsUnit* Target)
547→{
548→    if (!Target || Target->bIsDead) return;
549→
550→    // 基础伤害计算
551→    int32 Damage = AttackPower;
552→
553→    // 伤害随机浮动（10% 范围）
554→    float RandomFactor = FMath::RandRange(0.9f, 1.1f);
555→    Damage = FMath::RoundToInt(Damage * RandomFactor);
556→
557→    // 应用伤害
558→    Target->TakeDamage(Damage);
559→
560→    // 消耗行动力
561→    ConsumeMovePoints(1);
562→}
