564→void ALFPTacticsUnit::HandleDeath()
565→{
566→    bIsDead = true;
567→
568→	// 广播死亡事件
569→    OnDeathDelegate.Broadcast();
570→
571→    // 蓝图事件
572→    OnDeath();
573→
574→    // 通知 GameMode 敌方单位被击杀（掉落追踪）
575→    if (IsEnemy())
576→    {
577→        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
578→        {
579→            GM->OnEnemyUnitKilled(this);
580→        }
581→    }
582→
583→    // 从格子上移除
584→    ALFPHexTile* CurrentTile = GetCurrentTile();
585→    if (CurrentTile)
586→    {
587→        CurrentTile->SetUnitOnTile(nullptr);
588→    }
589→
590→    // 从回合系统中移除
591→    if (ALFPTurnManager* TurnManager = GetTurnManager())
592→    {
593→        TurnManager->UnregisterUnit(this);
594→    }
595→
596→    // 禁用碰撞
597→    SetActorEnableCollision(false);
598→
599→    // 延迟销毁
600→    FTimerHandle TimerHandle;
601→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this]()
602→        {
603→            Destroy();
604→        }, 2.0f, false);
605→}
