631→ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
632→{
633→    // 获取所有玩家单位
634→    TArray<AActor*> PlayerUnits;
635→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
636→
637→    ALFPTacticsUnit* BestTarget = nullptr;
638→    float BestThreatValue = -MAX_FLT;
639→
640→    for (AActor* Actor : PlayerUnits)
641→    {
642→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
643→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
644→        {
645→            float ThreatValue = CalculateThreatValue(Unit);
646→            if (ThreatValue > BestThreatValue)
647→            {
648→                BestThreatValue = ThreatValue;
649→                BestTarget = Unit;
650→            }
651→        }
652→    }
653→
654→    return BestTarget;
655→}
