657→ALFPHexTile* ALFPTacticsUnit::FindBestMovementTile(ALFPTacticsUnit* Target)
658→{
659→    ALFPHexGridManager* GridManager = GetGridManager();
660→    if (!GridManager)
661→    {
662→        return nullptr;
663→    }
664→    // 获取所有可移动位置
665→    MovementRangeTiles = GridManager->GetTilesInRange(GetCurrentTile(), GetCurrentMovePoints());
666→
667→    ALFPHexTile* BestTile = nullptr;
668→    float BestPositionValue = -MAX_FLT;
669→
670→    for (ALFPHexTile* Tile : MovementRangeTiles)
671→    {
672→        // 跳过有单位的格子
673→        if (Tile->GetUnitOnTile()) continue;
674→
675→        float PositionValue = CalculatePositionValue(Tile, Target);
676→        if (PositionValue > BestPositionValue)
677→        {
678→            BestPositionValue = PositionValue;
679→            BestTile = Tile;
680→        }
681→    }
682→
683→    return BestTile;
684→}
