686→float ALFPTacticsUnit::CalculateThreatValue(ALFPTacticsUnit* Target)
687→{
688→    // 威胁值 = 目标攻击力
689→    float ThreatValue = Target->GetAttackPower();
690→
691→    // 距离因素（越近威胁越大）
692→    int32 Distance = FLFPHexCoordinates::Distance(
693→        GetCurrentCoordinates(),
694→        Target->GetCurrentCoordinates()
695→    );
696→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
697→
698→    //// 应用行为数据
699→    //if (BehaviorData)
700→    //{
701→    //    if (BehaviorData->bPrioritizeWeakTargets)
702→    //    {
703→    //        // 增加对低血量目标的权重
704→    //        float HealthRatio = (float)Target->GetCurrentHealth() / Target->GetMaxHealth();
705→    //        // 血量越低，威胁值越高
706→    //    }
707→
708→    //    // 应用攻击性系数
709→    //    ThreatValue *= BehaviorData->Aggressiveness;
710→    //}
711→
712→    return ThreatValue * DistanceFactor;
713→}
