770→TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
771→{
772→    TArray<ALFPHexTile*> AttackRangeTiles;
773→
774→    if (ALFPHexGridManager* GridManager = GetGridManager())
775→    {
776→        // 近战攻击范围
777→        if (bMeleeAttack)
778→        {
779→            // 获取相邻格子
780→            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
781→            for (const FLFPHexCoordinates& Coord : Neighbors)
782→            {
783→                FLFPHexCoordinates Key(Coord.Q, Coord.R);
784→                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
785→                {
786→                    AttackRangeTiles.Add(Tile);
787→                }
788→            }
789→        }
790→        // 远程攻击范围
791→        else
792→        {
793→            // 获取攻击范围内的所有格子
794→            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
795→
796→            for (ALFPHexTile* Tile : TilesInRange)
797→            {
798→                AttackRangeTiles.Add(Tile);
799→            }
800→        }
801→    }
802→
803→    return AttackRangeTiles;
804→}
