806→bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
807→{
808→    if (!Target || !Target->GetCurrentTile()) return false;
809→
810→    // 计算距离
811→    int32 Distance = FLFPHexCoordinates::Distance(
812→        CurrentCoordinates,
813→        Target->GetCurrentCoordinates()
814→    );
815→
816→    // 近战攻击判定
817→    if (bMeleeAttack)
818→    {
819→        return Distance == 1; // 相邻格子
820→    }
821→    // 远程攻击判定
822→    else
823→    {
824→        return Distance >= 2 && Distance <= AttackRange;
825→    }
826→}
