 140→void ALFPTacticsPlayerController::Tick(float DeltaTime)
 141→{
 142→    Super::Tick(DeltaTime);
 143→
 144→    if (bIsDragging)
 145→    {
 146→        DragTime += DeltaTime;
 147→    }
 148→
 149→    // 布置阶段：更新预览单位跟随鼠标
 150→    if (bIsInDeployment && bIsPlacingUnit && PlacingUnitPreview)
 151→    {
 152→        FVector WorldOrigin, WorldDirection;
 153→        DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
 154→        if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
 155→        {
 156→            float T = -WorldOrigin.Z / WorldDirection.Z;
 157→            FVector HitPoint = WorldOrigin + WorldDirection * T;
 158→            PlacingUnitPreview->SetActorLocation(FVector(HitPoint.X, HitPoint.Y, 20.f));
 159→        }
 160→    }
 161→
 162→    // 更新相机位置
 163→    if (GridManager)
 164→    {
 165→        FVector CameraLocation = GridManager->GetActorLocation() + CameraOffset;
 166→        FRotator CameraRotation(CameraRotationPitchAngle, CameraRotationYawAngle, 0);
 167→        SetControlRotation(CameraRotation);
 168→
 169→        // 计算相机位置偏移
 170→        FVector DirectionOffset = CameraRotation.Vector() * CurrentZoom;
 171→        DirectionOffset.Z = CurrentZoom * 0.5f; // 高度由缩放比例决定
 172→
 173→        // 设置相机位置
 174→        APawn* ControlledPawn = GetPawn();
 175→        if (ControlledPawn)
 176→        {
 177→            FVector TargetLocation = CameraLocation + DirectionOffset;
 178→            if (bSnapCameraNextFrame)
 179→            {
 180→                // 首帧直接跳到目标位置，避免切场景后相机大幅滑动
 181→                ControlledPawn->SetActorLocation(TargetLocation);
 182→                bSnapCameraNextFrame = false;
 183→            }
 184→            else
 185→            {
 186→                ControlledPawn->SetActorLocation(FMath::VInterpTo(
 187→                    ControlledPawn->GetActorLocation(),
 188→                    TargetLocation,
 189→                    DeltaTime,
 190→                    5.0f // 插值速度
 191→                ));
 192→            }
 193→        }
 194→
 195→        // 获取鼠标位置
 196→        float MouseX, MouseY;
 197→        if (GetMousePosition(MouseX, MouseY))
 198→        {
 199→            FVector2D ScreenPosition(MouseX, MouseY);
 200→            // 获取光标下的六边形Tile
 201→            ALFPHexTile* HoveredTile = GridManager->GetHexTileUnderCursor(ScreenPosition, this);
 202→            // 处理鼠标悬停逻辑
 203→            if (HoveredTile != LastHoveredTile)
 204→            {
 205→                if (LastHoveredTile)
 206→                {
 207→                    //LastHoveredTile->OnMouseExit();
 208→                }
 209→
 210→                if (HoveredTile)
 211→                {
 212→                    SelectTile(HoveredTile);
 213→                    //HoveredTile->OnMouseEnter();
 214→                }
 215→
 216→                LastHoveredTile = HoveredTile;
 217→            }
 218→
 219→            // 敌人计划预览：检测悬停的格子上是否有带行动计划的敌人
 220→            if (CachedBattlePhase == EBattlePhase::BP_EnemyPlanning || CachedBattlePhase == EBattlePhase::BP_ActionPhase)
 221→            {
 222→                ALFPTacticsUnit* HoveredEnemy = nullptr;
 223→                if (LastHoveredTile)
 224→                {
 225→                    ALFPTacticsUnit* UnitOnTile = LastHoveredTile->GetUnitOnTile();
 226→                    if (UnitOnTile && UnitOnTile->IsEnemy() && UnitOnTile->HasActionPlan())
 227→                    {
 228→                        HoveredEnemy = UnitOnTile;
 229→                    }
 230→                }
 231→
 232→                if (HoveredEnemy && HoveredEnemy != PreviewedEnemy)
 233→                {
 234→                    HideEnemyPlanPreview();
 235→                    ShowEnemyPlanPreview(HoveredEnemy);
 236→                }
 237→                else if (!HoveredEnemy && PreviewedEnemy)
 238→                {
 239→                    HideEnemyPlanPreview();
 240→                }
 241→            }
 242→        }
 243→    }
 244→
 245→    // 更新地图视觉效果
 246→    if (LastControlState != CurrentControlState)
 247→    {
 248→        switch (CurrentControlState)
 249→        {
 250→        case EPlayControlState::MoveState:
 251→            break;
 252→        case EPlayControlState::SkillReleaseState:
 253→            break;
 254→        default:
 255→            break;
 256→        }
 257→    }
 258→}
