 321→void ALFPTacticsPlayerController::OnConfirmAction(const FInputActionValue& Value)
 322→{
 323→    bIsDragging = false;
 324→    if (DragTime > DragThresholdTime)
 325→    {
 326→        DragTime = 0.f;
 327→        return;
 328→    }
 329→    DragTime = 0.f;
 330→
 331→    // 布置阶段优先处理
 332→    if (bIsInDeployment)
 333→    {
 334→        if (bIsPlacingUnit)
 335→        {
 336→            // 正在放置单位：检测是否点击了空闲出生点
 337→            if (LastHoveredTile && PlayerSpawnTiles.Contains(LastHoveredTile)
 338→                && !LastHoveredTile->IsOccupied())
 339→            {
 340→                PlaceUnit(LastHoveredTile);
 341→            }
 342→        }
 343→        else
 344→        {
 345→            // 不在放置模式：检测是否点击了已放置的单位（拾起）
 346→            FHitResult HitResult;
 347→            GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
 348→            ALFPTacticsUnit* ClickedUnit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
 349→            if (ClickedUnit && DeployedUnits.Contains(ClickedUnit))
 350→            {
 351→                PickupDeployedUnit(ClickedUnit);
 352→            }
 353→        }
 354→        return;
 355→    }
 356→
 357→    // 编辑器模式优先处理
 358→    if (MapEditorComponent && MapEditorComponent->IsEditorActive())
 359→    {
 360→        if (LastHoveredTile)
 361→        {
 362→            MapEditorComponent->ApplyToolToTile(LastHoveredTile);
 363→        }
 364→        else if (GridManager && MapEditorComponent->GetCurrentTool() == ELFPMapEditorTool::MET_AddTile)
 365→        {
 366→            // 对空白区域添加格子：射线投射到 Z=0 平面计算坐标
 367→            FVector WorldOrigin, WorldDirection;
 368→            DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
 369→            if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
 370→            {
 371→                float T = -WorldOrigin.Z / WorldDirection.Z;
 372→                FVector HitPoint = WorldOrigin + WorldDirection * T;
 373→                FVector2D LocalLoc(
 374→                    HitPoint.X - GridManager->GetActorLocation().X,
 375→                    HitPoint.Y - GridManager->GetActorLocation().Y
 376→                );
 377→                FLFPHexCoordinates Coord = FLFPHexCoordinates::FromWorldLocation(
 378→                    LocalLoc, GridManager->GetHexSize(), GridManager->GetVerticalScale());
 379→                MapEditorComponent->ApplyToolToCoord(Coord.Q, Coord.R);
 380→            }
 381→        }
 382→        return;
 383→    }
 384→
 385→    if (SelectedUnit && SelectedTile)
 386→    {
 387→        if (bIsAttacking)
 388→        {
 389→            // 获取鼠标位置
 390→            float MouseX, MouseY;
 391→            GetMousePosition(MouseX, MouseY);
 392→            FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
 393→
 394→            FHitResult HitResult;
 395→            GetHitResultAtScreenPosition(SelectionEnd, ECC_Visibility, false, HitResult);
 396→
 397→            if (HitResult.bBlockingHit)
 398→            {
 399→                // 尝试选中单位
 400→                ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
 401→                if (Unit)
 402→                {
 403→                    AttackTarget(SelectedUnit, Unit);
 404→                    return;
 405→                }
 406→            }
 407→        }
 408→        else if (bIsReleaseSkill && CurrentSelectedSkill)
 409→        {
 410→            ExecuteSkill(CurrentSelectedSkill);
 411→        }
 412→        else
 413→        {
 414→            ConfirmMove();
 415→        }
 416→    }
 417→    else if (SelectedUnit)
 418→    {
 419→        // 如果没有选中目标格子，显示可移动范围
 420→        //ShowMovementRange(true);
 421→    }
 422→}
