 481→void ALFPTacticsPlayerController::OnCameraPan(const FInputActionValue& Value)
 482→{
 483→    // 获取输入值（WASD/方向键）
 484→    const FVector2D PanValue = Value.Get<FVector2D>();
 485→
 486→    // 计算移动方向（基于当前相机旋转）
 487→    FRotator CameraRotation(CameraRotationPitchAngle, CameraRotationYawAngle, 0);
 488→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
 489→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
 490→
 491→    // 计算移动偏移
 492→    FVector PanDirection = (Forward * PanValue.Y) + (Right * PanValue.X);
 493→    PanDirection.Z = 0;
 494→    PanDirection.Normalize();
 495→
 496→    // 应用移动
 497→    CameraOffset += PanDirection * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
 498→}
