 507→void ALFPTacticsPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
 508→{
 509→    if (!bIsDragging) return;
 510→
 511→    // 获取当前鼠标位置
 512→    FVector2D CurrentMousePosition;
 513→    GetMousePosition(CurrentMousePosition.X, CurrentMousePosition.Y);
 514→
 515→    // 计算鼠标移动偏移
 516→    FVector2D MouseDelta = CurrentMousePosition - DragStartPosition;
 517→
 518→    // 反转Y轴（屏幕Y轴向下，世界Y轴向上）
 519→    MouseDelta.Y = -MouseDelta.Y;
 520→
 521→    // 计算移动方向（基于当前相机旋转）
 522→    FRotator CameraRotation(0, CameraRotationYawAngle, 0);
 523→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
 524→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
 525→
 526→    // 计算移动偏移
 527→    FVector PanDirection = (Right * -MouseDelta.X) + (Forward * -MouseDelta.Y);
 528→    //PanDirection.Normalize();
 529→
 530→    // 应用移动
 531→    CameraOffset += PanDirection * CameraDragSpeed;
 532→
 533→    // 更新起始位置为当前位置
 534→    DragStartPosition = CurrentMousePosition;
 535→}
