 724→bool ALFPTacticsPlayerController::AttackTarget(ALFPTacticsUnit* Attacker, ALFPTacticsUnit* Target)
 725→{
 726→    if (!Attacker || !Target || !Attacker->CanAct())
 727→    {
 728→        return false;
 729→    }
 730→
 731→    // 计算攻击代价
 732→    const int32 AttackCost = 1;
 733→
 734→    bIsAttacking = false;
 735→    CurrentControlState = EPlayControlState::MoveState;
 736→
 737→    if (!Attacker->HasEnoughActionPoints(AttackCost))
 738→    {
 739→        return false;
 740→    }
 741→
 742→    // 执行攻击逻辑
 743→    bool bAttackSucceed = Attacker->AttackTarget(Target);
 744→
 745→    if (bAttackSucceed)
 746→    {
 747→		// 消耗行动力
 748→		Attacker->ConsumeActionPoints(AttackCost);
 749→        ShowUnitRange(EUnitRange::UR_Default);
 750→    }
 751→    else
 752→    {
 753→        ShowUnitRange(EUnitRange::UR_Move);
 754→    }
 755→
 756→    // 通知回合管理器单位完成行动
 757→    if (!Attacker->HasEnoughActionPoints(1))
 758→    {
 759→		if (bAttackSucceed)
 760→		{
 761→            SkipTurn(Attacker);
 762→		}
 763→    }
 764→
 765→    return bAttackSucceed;
 766→}
