1046→void ALFPTacticsPlayerController::StartPlacingUnit(int32 PartyIndex)
1047→{
1048→    // 如果正在放置其他单位，先取消
1049→    if (bIsPlacingUnit)
1050→    {
1051→        CancelPlacing();
1052→    }
1053→
1054→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
1055→    if (!GI || !GI->UnitRegistry) return;
1056→    if (!GI->PartyUnits.IsValidIndex(PartyIndex)) return;
1057→
1058→    // 如果该单位已经放置，先拾起
1059→    if (DeployedUnits.IsValidIndex(PartyIndex) && DeployedUnits[PartyIndex])
1060→    {
1061→        PickupDeployedUnit(DeployedUnits[PartyIndex]);
1062→    }
1063→
1064→    const FLFPUnitEntry& Entry = GI->PartyUnits[PartyIndex];
1065→    TSubclassOf<ALFPTacticsUnit> UnitClass = GI->UnitRegistry->GetUnitClass(Entry.TypeID);
1066→    if (!UnitClass) return;
1067→
1068→    // 在鼠标位置生成预览单位
1069→    FVector UnitSpawnLoc = FVector(0, 0, 50.f);
1070→    FActorSpawnParameters SpawnParams;
1071→    PlacingUnitPreview = GetWorld()->SpawnActor<ALFPTacticsUnit>(UnitClass, UnitSpawnLoc, FRotator::ZeroRotator, SpawnParams);
1072→
1073→    if (PlacingUnitPreview)
1074→    {
1075→        PlacingUnitPreview->Affiliation = EUnitAffiliation::UA_Player;
1076→        PlacingUnitPreview->UnitTypeID = Entry.TypeID;
1077→        PlacingUnitPreview->UnitTier = Entry.Tier;
1078→    }
1079→
1080→    PlacingPartyIndex = PartyIndex;
1081→    bIsPlacingUnit = true;
1082→
1083→    if (DeploymentWidget)
1084→    {
1085→        DeploymentWidget->MarkUnitSelecting(PartyIndex);
1086→    }
1087→
1088→    UE_LOG(LogTemp, Log, TEXT("开始放置单位 %s（索引 %d）"), *Entry.TypeID.ToString(), PartyIndex);
1089→}
