1091→void ALFPTacticsPlayerController::PlaceUnit(ALFPHexTile* Tile)
1092→{
1093→    if (!Tile || !PlacingUnitPreview || PlacingPartyIndex < 0) return;
1094→
1095→    // 放置到格子上
1096→    FVector TileLocation = Tile->GetActorLocation() + FVector(0, 0, 50.f);
1097→    PlacingUnitPreview->SetActorLocation(TileLocation);
1098→    PlacingUnitPreview->SetCurrentCoordinates(Tile->GetCoordinates());
1099→
1100→    // 更新格子占用
1101→    Tile->SetIsOccupied(true);
1102→    Tile->SetUnitOnTile(PlacingUnitPreview);
1103→
1104→    // 记录到已布置列表
1105→    if (DeployedUnits.IsValidIndex(PlacingPartyIndex))
1106→    {
1107→        DeployedUnits[PlacingPartyIndex] = PlacingUnitPreview;
1108→    }
1109→
1110→    // 更新 UI
1111→    if (DeploymentWidget)
1112→    {
1113→        DeploymentWidget->MarkUnitPlaced(PlacingPartyIndex, true);
1114→    }
1115→
1116→    UE_LOG(LogTemp, Log, TEXT("放置单位到格子 (%d, %d)"), Tile->GetCoordinates().Q, Tile->GetCoordinates().R);
1117→
1118→    // 重置放置状态
1119→    PlacingUnitPreview = nullptr;
1120→    PlacingPartyIndex = -1;
1121→    bIsPlacingUnit = false;
1122→}
