1136→void ALFPTacticsPlayerController::PickupDeployedUnit(ALFPTacticsUnit* Unit)
1137→{
1138→    if (!Unit) return;
1139→
1140→    // 找到对应的 PartyIndex
1141→    int32 FoundIndex = DeployedUnits.Find(Unit);
1142→    if (FoundIndex == INDEX_NONE) return;
1143→
1144→    // 清除格子占用
1145→    ALFPHexTile* OldTile = Unit->GetCurrentTile();
1146→    if (OldTile)
1147→    {
1148→        OldTile->SetIsOccupied(false);
1149→        OldTile->SetUnitOnTile(nullptr);
1150→    }
1151→
1152→    // 设置为跟随鼠标的预览
1153→    PlacingUnitPreview = Unit;
1154→    PlacingPartyIndex = FoundIndex;
1155→    bIsPlacingUnit = true;
1156→
1157→    // 清除已布置记录
1158→    DeployedUnits[FoundIndex] = nullptr;
1159→
1160→    // 更新 UI
1161→    if (DeploymentWidget)
1162→    {
1163→        DeploymentWidget->MarkUnitPlaced(FoundIndex, false);
1164→    }
1165→
1166→    UE_LOG(LogTemp, Log, TEXT("拾起已放置的单位（索引 %d）"), FoundIndex);
1167→}
