1169→void ALFPTacticsPlayerController::ConfirmDeployment()
1170→{
1171→    if (!bIsInDeployment) return;
1172→
1173→    // 取消高亮
1174→    for (ALFPHexTile* Tile : PlayerSpawnTiles)
1175→    {
1176→        if (Tile)
1177→        {
1178→            Tile->SetMovementHighlight(false);
1179→        }
1180→    }
1181→    PlayerSpawnTiles.Empty();
1182→
1183→    // 移除布置 UI
1184→    if (DeploymentWidget)
1185→    {
1186→        DeploymentWidget->OnUnitSelected.RemoveDynamic(this, &ALFPTacticsPlayerController::StartPlacingUnit);
1187→        DeploymentWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1188→        DeploymentWidget->RemoveFromParent();
1189→    }
1190→
1191→    bIsInDeployment = false;
1192→    bIsPlacingUnit = false;
1193→
1194→    // 通知 TurnManager 结束布置阶段
1195→    ALFPTurnManager* TurnManager = GetTurnManager();
1196→    if (TurnManager)
1197→    {
